CustomField.formula:
IF( ISBLANK( TEXT( Status_Override__c ) ),
	IF( TODAY() > End_Date__c,
		'Completed',
		IF( TODAY() >=  Start_Date__c,
			IF( NOW() >=  Enrollment_Open_Date_Calculated__c && (ISNULL( Enrollment_Close_Date_Calculated__c) || NOW() <=  Enrollment_Close_Date_Calculated__c),
				'Running (Enrollment Opened)',
				'Running'
			),
			IF( NOW() >  Enrollment_Close_Date_Calculated__c,
				'Enrollment Closed',
				IF( NOW() >=  Enrollment_Open_Date_Calculated__c,
					'Enrollment Opened',
					IF( NOT(ISNULL( Pre_enrollment_Open_Date_Calculated__c)) && NOW() >=  Pre_enrollment_Open_Date_Calculated__c,
						'Pre-enrollment Opened',
						'Not Started'
					)
				)
			)
		)
	),
	TEXT(  Status_Override__c )
)
